import org.junit.jupiter.api.Test;

class StreamBindingSchemaTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void statementPatternsAndScalarSubqueriesExposeOnlyStreamOutputs() {
		StatementPattern stream = pattern("entity", "value");
		StatementPattern probe = pattern("entity", "probeLocal");

		assertSchema(stream, Set.of("entity", "value"), Set.of("entity", "value"));
		assertSchema(new Filter(stream, new Exists(probe)), Set.of("entity", "value"),
				Set.of("entity", "value"));
	}

	@Test
	void binaryOperatorsUseTheirDeclaredOutputContracts() {
		StatementPattern left = pattern("shared", "leftOnly");
		StatementPattern right = pattern("shared", "rightOnly");

		assertSchema(new Join(left.clone(), right.clone()), Set.of("shared", "leftOnly", "rightOnly"),
				Set.of("shared", "leftOnly", "rightOnly"));
		assertSchema(new LeftJoin(left.clone(), right.clone()), Set.of("shared", "leftOnly", "rightOnly"),
				Set.of("shared", "leftOnly"));
		assertSchema(new Union(left.clone(), right.clone()), Set.of("shared", "leftOnly", "rightOnly"),
				Set.of("shared"));
		assertSchema(new Difference(left.clone(), right.clone()), Set.of("shared", "leftOnly"),
				Set.of("shared", "leftOnly"));
		assertSchema(new Intersection(left, right), Set.of("shared"), Set.of("shared"));
	}

	@Test
	void unaryOperatorsSeparateOutputsFromScalarRequirements() {
		StatementPattern stream = pattern("entity", "value");
		Extension extension = new Extension(stream.clone(),
				new ExtensionElem(new Var("externalInput"), "derived"));
		Projection projection = new Projection(stream.clone(),
				new ProjectionElemList(new ProjectionElem("value", "projectedValue")));
		Group group = new Group(stream.clone(), List.of("entity"),
				List.of(new GroupElem("count", new Count(new Var("value"), true))));

		assertSchema(extension, Set.of("entity", "value", "derived"), Set.of("entity", "value"));
		assertSchema(projection, Set.of("projectedValue"), Set.of("projectedValue"));
		assertSchema(group, Set.of("entity", "count"), Set.of("entity"));
		assertSchema(new Slice(stream, 0, 10), Set.of("entity", "value"), Set.of("entity", "value"));
	}

	private static StatementPattern pattern(String subject, String object) {
		return new StatementPattern(new Var(subject), new Var("predicateConstant", VF.createIRI("urn:predicate")),
				new Var(object));
	}

	private static void assertSchema(TupleExpr tupleExpr, Set<String> possible, Set<String> assured) {
		assertEquals(new StreamBindingSchema(possible, assured), StreamBindingSchema.from(tupleExpr));
	}
}
